# -*- coding: utf-8 -*-
import base64, os
folder = os.path.dirname(os.path.abspath(__file__))
INDEX_B64 = ""
CSS_B64   = ""
files = {"index.html": INDEX_B64, "style.css": CSS_B64}
for filename, b64data in files.items():
    path = os.path.join(folder, filename)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64data))
    print("저장 완료:", filename)
print("")
print("모든 파일 저장 완료! 이제 git push 하시면 됩니다.")